mapper.select:
SELECT /* @SQLID=SUB0601_01-02_1#Sql004 */ BRANCH_CODE, BRANCH_KIND BRANCH_CLASS, BRANCH_NAME, CREATE_DATE CREATE_TIME, CREATE_BY CREATE_USER, UPDATE_DATE UPDATE_TIME, UPDATE_BY UPDATE_USER, DELETE_DATE DELETE_TIME, DELETE_FLG FROM BRANCH WHERE DELETE_FLG = '0'
AND BRANCH_KIND = #{req.branchClass}
ORDER BY BRANCH_CODE

SELECT /* @SQLID=SUB0601_01-02_1#Sql005 */ DISTINCT B.BROKER_CODE, B.BROKER_BRANCH_CODE SUB_BROKER_ID, B.BROKER_BRANCH_KIND BRANCH_CLASS, B.BRANCH_NAME BRANCH_NAME_BROKER_NAME FROM BRANCH_MEDIATE_INFO A INNER JOIN MEDIATE_BRANCH B ON A.BROKER_CODE = B.BROKER_CODE AND B.BROKER_BRANCH_KIND = '00' AND B.DELETE_FLG = '0' AND A.DELETE_FLG = '0'
WHERE A.BRANCH_CODE = #{req.branchCode}
ORDER BY B.BROKER_CODE, B.BROKER_BRANCH_CODE

SELECT /* @SQLID=SUB0601_01-02_1#Sql006 */ DISTINCT A.BROKER_BRANCH_CODE SUB_BROKER_ID, A.BRANCH_NAME BRANCH_NAME_BROKER_NAME FROM MEDIATE_BRANCH A WHERE A.DELETE_FLG = '0'
AND A.BROKER_CODE = #{req.brokerCode}
AND A.BROKER_BRANCH_KIND != '00' ORDER BY A.BROKER_BRANCH_CODE

SELECT /* @SQLID=SUB0601_01-02_1#Sql007 */ A.BROKER_CHARGE_CODE, A.BROKER_CHARGE_NAME EMPLOYEE_NAME FROM MEDIATE_CHARGE_INFO A WHERE A.DELETE_FLG = '0'
AND A.BROKER_CODE = #{req.brokerCode}
AND A.BROKER_BRANCH_CODE = #{req.subBrokerCode}
